<template>
    <section id="kabar" class="container">
            <div class="row my-5">
                <div class="col-12"><h1 class="fw-semibold text-center">Berita</h1></div>
            </div>
            <div class="row my-5">
                <!-- loop dari sini -->
                <div  v-for="kabar in data" :key="kabar.id" class="col-md-12 col-xs-12 col-sm-12 col-lg-6 mb-4">
                    <div data-aos="fade-down" data-aos-duration="800" data-aos-delay="1000" class="card  mx-auto">
                        <div class="card-header">
                            <img v-bind:src="'http://wawanindrawan.nurulfikri.com/capstone-km/'+kabar.thumbnail" class="img-fluid shadow-md" style="width:70%;background:#eaeaea">
                        </div>
                        <div class="card-body px-2 mx-auto">
                            <router-link
                                :to="{name: 'ppdb.artikel', params:{id:kabar.id}}" class="text-decoration-none">
                            <h3 class="text-hijau">{{ kabar.judul }}</h3>
                                
                            </router-link>
                            <span class="text-secondary small py-2"><i class="bi bi-calendar"></i> {{ kabar.tanggal }} {{ kabar.kategori_id }}</span>
                            <p class="mt-3">{{ kabar.isi }}</p>
                        </div>
                    </div>
                </div>
                <!-- sampe sini -->
            </div>
        </section>
</template>

<script>

import axios from 'axios'
import { onMounted} from 'vue';
import AOS from 'aos';
import 'aos/dist/aos.css'

export default{
    setup(){
        onMounted(()=>{
            AOS.init();
        })
    },
    name : 'BeritaComponent',
     data(){
        return{
            data: []
        }
    },
    async mounted(){
        const berita = await axios.get('http://wawanindrawan.nurulfikri.com/capstone-km/api/berita')
        this.data = berita.data.berita;
        
    },
}

</script>